import json
from typing import Any, Optional, Dict, List
from dataclasses import dataclass, field
from datetime import datetime
import random

# ============================================================================
# AGENT LOOP ARCHITECTURE WITH TOOL USE AND STATE MANAGEMENT
# ============================================================================

@dataclass
class CricketMatch:
    """Represents the current state of a cricket match."""
    match_id: str
    team_batting: str
    team_bowling: str
    current_score: int
    wickets_down: int
    overs_completed: float
    available_tools: List[str] = field(default_factory=list)
    action_history: List[Dict[str, Any]] = field(default_factory=list)

    def __repr__(self):
        return f"Match({self.team_batting} {self.current_score}/{self.wickets_down} after {self.overs_completed} overs)"


class MatchAnalysisTool:
    """Base class for cricket match analysis tools."""
    def __init__(self, name: str):
        self.name = name

    def execute(self, **kwargs) -> Dict[str, Any]:
        raise NotImplementedError()


class BattingFormAnalyzer(MatchAnalysisTool):
    """Analyzes batting form of current batsmen."""
    def __init__(self):
        super().__init__("batting_form_analyzer")
        # Sample data: player recent scores
        self.player_data = {
            "Rohit Sharma": {"recent_scores": [45, 32, 78, 15], "form": "good"},
            "Virat Kohli": {"recent_scores": [89, 12, 67, 94], "form": "excellent"},
            "MS Dhoni": {"recent_scores": [28, 45, 19, 52], "form": "moderate"},
        }

    def execute(self, player_name: str, **kwargs) -> Dict[str, Any]:
        if player_name in self.player_data:
            data = self.player_data[player_name]
            avg = sum(data["recent_scores"]) / len(data["recent_scores"])
            return {
                "success": True,
                "player": player_name,
                "average_recent_score": avg,
                "form": data["form"],
                "recommendation": "aggressive" if avg > 50 else "cautious"
            }
        return {"success": False, "error": f"Player {player_name} not found"}


class FieldPositionAnalyzer(MatchAnalysisTool):
    """Analyzes optimal field placement."""
    def __init__(self):
        super().__init__("field_position_analyzer")

    def execute(self, batsman_strength: str, bowler_type: str, **kwargs) -> Dict[str, Any]:
        field_recommendations = {
            ("aggressive", "fast"): ["slips", "gully", "short_midwicket"],
            ("aggressive", "spin"): ["close_to_bat", "leg_trap"],
            ("defensive", "fast"): ["deep_point", "deep_mid_off"],
            ("defensive", "spin"): ["deep_fine_leg", "deep_midwicket"],
        }
        key = (batsman_strength, bowler_type)
        positions = field_recommendations.get(key, ["standard_positions"])
        return {
            "success": True,
            "recommended_positions": positions,
            "reasoning": f"For {batsman_strength} batter vs {bowler_type} bowler"
        }


class BowlingAnalyzer(MatchAnalysisTool):
    """Analyzes bowling performance and economy."""
    def __init__(self):
        super().__init__("bowling_analyzer")
        self.bowler_data = {
            "Jasprit Bumrah": {"avg_economy": 5.2, "recent_wickets": 3},
            "Yuzvendra Chahal": {"avg_economy": 6.8, "recent_wickets": 2},
            "Ravichandran Ashwin": {"avg_economy": 4.1, "recent_wickets": 4},
        }

    def execute(self, bowler_name: str, overs_bowled: int = 0, **kwargs) -> Dict[str, Any]:
        if bowler_name in self.bowler_data:
            data = self.bowler_data[bowler_name]
            fatigue_factor = min(overs_bowled / 10.0, 1.0)  # Fatigue increases with overs
            adjusted_economy = data["avg_economy"] * (1 + fatigue_factor * 0.2)
            return {
                "success": True,
                "bowler": bowler_name,
                "economy_rate": adjusted_economy,
                "recent_wickets": data["recent_wickets"],
                "fatigue_level": "fresh" if fatigue_factor < 0.3 else ("moderate" if fatigue_factor < 0.7 else "high")
            }
        return {"success": False, "error": f"Bowler {bowler_name} not found"}


class MatchDecisionAgent:
    """Agent for making tactical cricket match decisions."""

    def __init__(self, match: CricketMatch):
        self.match = match
        self.tools = {
            "batting_form_analyzer": BattingFormAnalyzer(),
            "field_position_analyzer": FieldPositionAnalyzer(),
            "bowling_analyzer": BowlingAnalyzer(),
        }
        self.iteration_count = 0
        self.max_iterations = 5

    def perceive(self) -> Dict[str, Any]:
        """STEP 1: Perceive current match state."""
        return {
            "score": self.match.current_score,
            "wickets": self.match.wickets_down,
            "overs": self.match.overs_completed,
            "available_tools": list(self.tools.keys()),
        }

    def reason(self, perception: Dict[str, Any]) -> Dict[str, Any]:
        """STEP 2: Reason about best action given perception."""
        # Simple heuristic: determine what information is needed
        score_rate = perception["score"] / max(perception["overs"], 0.1)

        if perception["overs"] < 6 and score_rate < 7:
            return {
                "action": "analyze_batsman_form",
                "target": "Rohit Sharma",
                "reasoning": "Early powerplay, slow scoring—analyze current batsman form"
            }
        elif perception["overs"] < 10:
            return {
                "action": "get_field_recommendation",
                "batsman_strength": "aggressive",
                "bowler_type": "fast",
                "reasoning": "Determine optimal field for aggressive phase"
            }
        else:
            return {
                "action": "check_bowler_status",
                "bowler": "Jasprit Bumrah",
                "overs_bowled": int(perception["overs"] / 2),
                "reasoning": "Check if premier bowler can continue or needs rest"
            }

    def act(self, decision: Dict[str, Any]) -> Dict[str, Any]:
        """STEP 3: Execute the tool call based on decision."""
        action_type = decision["action"]

        if action_type == "analyze_batsman_form":
            tool = self.tools["batting_form_analyzer"]
            result = tool.execute(player_name=decision["target"])
        elif action_type == "get_field_recommendation":
            tool = self.tools["field_position_analyzer"]
            result = tool.execute(
                batsman_strength=decision["batsman_strength"],
                bowler_type=decision["bowler_type"]
            )
        elif action_type == "check_bowler_status":
            tool = self.tools["bowling_analyzer"]
            result = tool.execute(
                bowler_name=decision["bowler"],
                overs_bowled=decision.get("overs_bowled", 0)
            )
        else:
            result = {"success": False, "error": "Unknown action"}

        return {"action": action_type, "result": result, "decision_context": decision}

    def observe(self, action_result: Dict[str, Any]) -> None:
        """STEP 4: Observe outcome and update state."""
        self.match.action_history.append({
            "iteration": self.iteration_count,
            "timestamp": datetime.now().isoformat(),
            "action": action_result["action"],
            "result": action_result["result"],
        })

    def should_continue(self) -> bool:
        """Determine if agent should continue looping."""
        # Stopping conditions:
        # 1. Max iterations reached
        # 2. Critical decision made (field set, bowler decided)
        # 3. Insufficient information (tool failures)

        if self.iteration_count >= self.max_iterations:
            return False

        last_action = self.match.action_history[-1] if self.match.action_history else None
        if last_action and last_action["result"].get("success"):
            # Successfully gathered information; move to execution phase
            return False

        return True

    def run(self) -> List[Dict[str, Any]]:
        """Execute the agent loop until stopping condition."""
        print(f"\n{'='*70}")
        print(f"MATCH DECISION AGENT STARTED - {self.match}")
        print(f"{'='*70}\n")

        while self.should_continue():
            self.iteration_count += 1
            print(f"--- ITERATION {self.iteration_count} ---")

            # Agent loop: Perceive → Reason → Act → Observe
            perception = self.perceive()
            print(f"1. PERCEIVE: {json.dumps(perception, indent=2)}")

            decision = self.reason(perception)
            print(f"2. REASON: {json.dumps(decision, indent=2)}")

            action_result = self.act(decision)
            print(f"3. ACT: {json.dumps(action_result, indent=2)}")

            self.observe(action_result)
            print(f"4. OBSERVE: Action recorded in history\n")

        print(f"{'='*70}")
        print(f"AGENT STOPPED - Iteration limit or convergence reached")
        print(f"Total iterations: {self.iteration_count}")
        print(f"Actions taken: {len(self.match.action_history)}")
        print(f"{'='*70}\n")

        return self.match.action_history


# ============================================================================
# MAIN EXECUTION
# ============================================================================

if __name__ == "__main__":
    # Create a match state
    match = CricketMatch(
        match_id="IND_vs_AUS_2024_T20",
        team_batting="India",
        team_bowling="Australia",
        current_score=42,
        wickets_down=0,
        overs_completed=5.3
    )

    # Initialize and run the agent
    agent = MatchDecisionAgent(match)
    action_history = agent.run()

    # Print final state and recommendations
    print("\nFINAL RECOMMENDATIONS:")
    print("-" * 70)
    for idx, action in enumerate(action_history, 1):
        result = action["result"]
        if result.get("success"):
            print(f"\n{idx}. {action['action'].upper()}")
            for key, value in result.items():
                if key != "success":
                    print(f"   {key}: {value}")

# Production-grade agent security with trust boundary enforcement
import hashlib
import json
from datetime import datetime
from enum import Enum
from typing import Any, Dict, List

class SecurityLevel(Enum):
    PUBLIC = "public"
    INTERNAL = "internal"
    RESTRICTED = "restricted"

class CricketAgentSecurityManager:
    """Manages trust boundaries for autonomous cricket strategy agents."""

    def __init__(self, agent_id: str, security_level: SecurityLevel):
        self.agent_id = agent_id
        self.security_level = security_level
        self.audit_log = []
        self.allowed_tools = self._init_allowed_tools()
        self.execution_context = {}
        self.rate_limit_tokens = 100

    def _init_allowed_tools(self) -> Dict[str, Dict[str, Any]]:
        """Define granular tool permissions by security level."""
        tools = {
            "analyze_bowling_patterns": {
                "allowed_levels": [SecurityLevel.PUBLIC, SecurityLevel.INTERNAL, SecurityLevel.RESTRICTED],
                "requires_auth": False,
                "rate_limit_per_hour": 1000
            },
            "modify_team_strategy": {
                "allowed_levels": [SecurityLevel.INTERNAL, SecurityLevel.RESTRICTED],
                "requires_auth": True,
                "rate_limit_per_hour": 10
            },
            "access_player_injury_data": {
                "allowed_levels": [SecurityLevel.RESTRICTED],
                "requires_auth": True,
                "rate_limit_per_hour": 5
            },
            "modify_match_rules": {
                "allowed_levels": [],  # Never allowed via agent
                "requires_auth": True,
                "rate_limit_per_hour": 0
            }
        }
        return tools

    def validate_tool_call(self, tool_name: str, parameters: Dict) -> tuple[bool, str]:
        """Validate if agent can call a specific tool."""
        if tool_name not in self.allowed_tools:
            return False, f"Tool '{tool_name}' unknown"

        tool_spec = self.allowed_tools[tool_name]

        # Check security level permission
        if self.security_level not in tool_spec["allowed_levels"]:
            self._audit_log_event(
                "DENIED", tool_name, parameters,
                f"Security level {self.security_level} not authorized"
            )
            return False, f"Security level insufficient for {tool_name}"

        # Check rate limiting
        if not self._check_rate_limit(tool_name):
            self._audit_log_event(
                "RATE_LIMITED", tool_name, parameters,
                "Rate limit exceeded"
            )
            return False, f"Rate limit exceeded for {tool_name}"

        # Validate parameter safety
        if not self._validate_parameters(tool_name, parameters):
            return False, f"Invalid parameters for {tool_name}"

        self._audit_log_event("APPROVED", tool_name, parameters, "Valid")
        return True, "Approved"

    def _check_rate_limit(self, tool_name: str) -> bool:
        """Check if agent has consumed its rate limit tokens."""
        if self.rate_limit_tokens <= 0:
            return False
        self.rate_limit_tokens -= 1
        return True

    def _validate_parameters(self, tool_name: str, parameters: Dict) -> bool:
        """Validate tool parameters against injection and overflow attacks."""
        # Example: prevent SQL injection in player_name field
        dangerous_chars = ["'", '"', ";", "--", "/*", "*/"]

        for key, value in parameters.items():
            if isinstance(value, str):
                for char in dangerous_chars:
                    if char in value:
                        return False
            elif isinstance(value, (int, float)):
                # Prevent extreme values
                if abs(value) > 1e10:
                    return False

        return True

    def _audit_log_event(self, event_type: str, tool_name: str, 
                        params: Dict, reason: str) -> None:
        """Log all tool invocation attempts for compliance."""
        log_entry = {
            "timestamp": datetime.utcnow().isoformat(),
            "agent_id": self.agent_id,
            "event_type": event_type,
            "tool_name": tool_name,
            "parameters_hash": hashlib.sha256(
                json.dumps(params, sort_keys=True).encode()
            ).hexdigest(),
            "reason": reason
        }
        self.audit_log.append(log_entry)

    def execute_tool_safely(self, tool_name: str, parameters: Dict) -> Dict:
        """Execute tool with full isolation and monitoring."""
        is_valid, message = self.validate_tool_call(tool_name, parameters)

        if not is_valid:
            return {
                "success": False,
                "error": message,
                "agent_id": self.agent_id
            }

        # Execute with isolated context (simplified)
        try:
            result = self._isolated_execution(tool_name, parameters)
            self._audit_log_event("EXECUTED", tool_name, parameters, "Success")
            return {
                "success": True,
                "result": result,
                "agent_id": self.agent_id
            }
        except Exception as e:
            self._audit_log_event("FAILED", tool_name, parameters, str(e))
            return {
                "success": False,
                "error": str(e),
                "agent_id": self.agent_id
            }

    def _isolated_execution(self, tool_name: str, parameters: Dict) -> Any:
        """Execute in isolated sandbox (simplified version)."""
        # In production: use containerization, timeouts, memory limits
        if tool_name == "analyze_bowling_patterns":
            return {"analysis": "Pace bowler trending left", "confidence": 0.87}
        elif tool_name == "modify_team_strategy":
            return {"strategy_id": "aggressive_batting_001", "applied": True}
        return {}

    def get_audit_trail(self) -> List[Dict]:
        """Return complete audit log for compliance review."""
        return self.audit_log.copy()

# Usage example
if __name__ == "__main__":
    # Create agents with different trust levels
    public_agent = CricketAgentSecurityManager(
        "virat_public_analyzer", SecurityLevel.PUBLIC
    )
    restricted_agent = CricketAgentSecurityManager(
        "coach_strategy_manager", SecurityLevel.RESTRICTED
    )

    # Test: Public agent tries to access injury data (should fail)
    success, msg = public_agent.validate_tool_call(
        "access_player_injury_data", {"player_id": "bumrah"}
    )
    print(f"Public agent injury access: {success} - {msg}")

    # Test: Restricted agent accesses injury data (should succeed)
    success, msg = restricted_agent.validate_tool_call(
        "access_player_injury_data", {"player_id": "bumrah"}
    )
    print(f"Restricted agent injury access: {success} - {msg}")

    # Test: Attempt tool never allowed
    success, msg = restricted_agent.validate_tool_call(
        "modify_match_rules", {"overs": 20}
    )
    print(f"Modify rules attempt: {success} - {msg}")

    # View audit trail
    print("\nAudit Trail:")
    for entry in restricted_agent.get_audit_trail():
        print(f"  {entry['timestamp']}: {entry['event_type']} - {entry['tool_name']}")
